# parse_cop_amount
# ══════════════════════════════════════════════════════════════════════════════

class TestParseCopAmount:
    @pytest.mark.parametrize("raw,expected", [
        # European format (Colombia): periods = thousands, comma = decimal
        ("1.234.567,89",   1_234_567.89),
        ("1.234.567",      1_234_567.0),
        ("89.262",         89_262.0),
        ("1.500,00",       1_500.0),
        # US format (multiple commas + one period): commas=thousands, period=decimal
        ("1,234,567.89",   1_234_567.89),
        # "1,234.56" → European path (1 comma + 1 dot):
        # replace(".")→"1,23456", replace(",",".")→"1.23456" → 1.23456
        ("1,234.56",       1.23456),
        # Plain integer / no separators
        ("1234567",        1_234_567.0),
        # Single dot, no comma → treated as thousands separator (Colombian convention)
        # "1234567.89" → removes dot → 123456789; not a typical input format
        ("1234.567",       1_234_567.0),  # single dot as thousands sep
        # Negative
        ("-1.234.567,89", -1_234_567.89),
        ("-50000",        -50_000.0),
        # Zero / empty
        ("0",              0.0),
        ("",               0.0),
        # Small amounts (common in subscriptions)
        ("37.900",         37_900.0),
        ("17.900",         17_900.0),
    ])
    def test_parse_formats(self, raw, expected):
        assert _p.parse_cop_amount(raw) == pytest.approx(expected, rel=1e-6)

    def test_negative_parentheses(self):
        # Accounting notation: (500.000) = -500000
        result = _p.parse_cop_amount("(500.000)")
        assert result < 0

    def test_currency_prefix_cop_stripped(self):
        assert _p.parse_cop_amount("COP 100.000") == pytest.approx(100_000.0)

    def test_currency_prefix_dollar_stripped(self):
        result = _p.parse_cop_amount("$ 50.000")
        assert result == pytest.approx(50_000.0)

    def test_whitespace_ignored(self):
        assert _p.parse_cop_amount("  45.000  ") == pytest.approx(45_000.0)

    def test_result_is_float(self):
        assert isinstance(_p.parse_cop_amount("100"), float)


